import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [list, setList] = useState([]);
  const [search, setSearch] = useState('');
  const [form, setForm] = useState({ name: '', skill: '', price: '', email: '' });

  const fetchData = async () => {
    const res = await fetch('http://localhost:5000/api/get');
    const data = await res.json();
    setList(data);
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdd = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:5000/api/add', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    alert("Registered!");
    setForm({ name: '', skill: '', price: '', email: '' });
    fetchData();
  };

  // --- NAVEEN FEATURE: DELETE ---
  const deleteFreelancer = async (id) => {
    if(window.confirm("Are you sure?")) {
      await fetch(`http://localhost:5000/api/delete/${id}`, { method: 'DELETE' });
      fetchData();
    }
  };

  // Filter logic for Search
  const filteredList = list.filter(f => 
    f.skill.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="container">
      <header><h1>Freelancer Hub Pro</h1></header>
      
      {/* SEARCH BAR */}
      <div className="search-box">
        <input type="text" placeholder="Search by Skill (e.g. Java, React)..." onChange={(e) => setSearch(e.target.value)} />
      </div>

      <div className="main-content">
        <div className="form-card">
          <h2>Register</h2>
          <form onSubmit={handleAdd}>
            <input type="text" value={form.name} placeholder="Name" required onChange={e => setForm({...form, name: e.target.value})} />
            <input type="text" value={form.skill} placeholder="Skill" required onChange={e => setForm({...form, skill: e.target.value})} />
            <input type="number" value={form.price} placeholder="Price/hr" required onChange={e => setForm({...form, price: e.target.value})} />
            <input type="email" value={form.email} placeholder="Email" required onChange={e => setForm({...form, email: e.target.value})} />
            <button type="submit">Join Now</button>
          </form>
        </div>

        <div className="list-container">
          <h2>Freelancers</h2>
          <div className="freelancer-grid">
            {filteredList.map(f => (
              <div className="freelancer-card" key={f._id}>
                <h3>{f.name}</h3>
                <p className="skill-tag">{f.skill}</p>
                <p><b>${f.price}/hr</b></p>
                <a href={`mailto:${f.email}`} className="btn-contact">Contact</a>
                <button className="btn-delete" onClick={() => deleteFreelancer(f._id)}>Remove</button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
export default App;
